Code.Terraform:
```hcl
resource "aws_sfn_state_machine" "<example_resource_name>" {
  name       = "<example_resource_name>"
  role_arn   = "arn:aws:iam::<account-id>:role/<example_role_name>"
  definition = jsonencode({ StartAt = "Pass", States = { Pass = { Type = "Pass", End = true } } })

  encryption_configuration {
    kms_key_id                        = "arn:aws:kms:<region>:<account-id>:key/<key-id>"  # Critical: customer-managed KMS key
    type                              = "CUSTOMER_MANAGED_KMS_KEY"                         # Critical: must be CUSTOMER_MANAGED_KMS_KEY
    kms_data_key_reuse_period_seconds = 300
  }
}
```
